class Solution {
    public String smallestNumber(String pattern) {
        StringBuilder sb = new StringBuilder();
        int n = pattern.length();
        int[] num = new int[n + 1];
        int idx = 0;
        for (int i = 0; i < n; i++) {
            if (pattern.charAt(i) == 'I') {
                int j = i;
                while (j < n && pattern.charAt(j) == 'I') j++;
                for (int k = 1; k <= j - i + 1; k++) {
                    num[idx++] = k;
                }
                i = j - 1;
            } else {
                num[idx++] = 1;
            }
        }
        if (pattern.charAt(n - 1) == 'D') {
            int j = n - 1;
            int k = 9;
            while (j >= 0 && pattern.charAt(j) == 'D') {
                num[j + 1] = k--;
                j--;
            }
        }
        for (int i = 0; i < n; i++) {
            if (pattern.charAt(i) == 'I') {
                int j = i;
                int k = num[i] + 1;
                while (j < n && pattern.charAt(j) == 'I') {
                    num[j + 1] = k++;
                    j++;
                }
            }
        }
        for (int i = 0; i <= n; i++) {
            sb.append(num[i]);
        }
        return sb.toString();
    }
}
